import React, { useState } from "react";
import "./ProductCard.css";

const ProductCard = ({ product, onAddToCart }) => {
  const [wished, setWished] = useState(false);
  const [added, setAdded] = useState(false);

  const discount = Math.round(
    ((product.originalPrice - product.price) / product.originalPrice) * 100
  );

  const handleAddToCart = () => {
    onAddToCart(product);
    setAdded(true);
    setTimeout(() => setAdded(false), 1800);
  };

  const renderStars = (rating) => {
    const full = Math.floor(rating);
    const half = rating % 1 >= 0.5;
    return (
      <div className="stars">
        {[...Array(full)].map((_, i) => <span key={i} className="star full">★</span>)}
        {half && <span className="star half">★</span>}
        {[...Array(5 - full - (half ? 1 : 0))].map((_, i) => (
          <span key={i} className="star empty">★</span>
        ))}
      </div>
    );
  };

  return (
    <div className="product-card">
      <div className="card-image-wrap">
        <img src={product.image} alt={product.name} className="card-img" loading="lazy" />

        {/* Badges */}
        <div className="card-badges">
          {product.badge && (
            <span className={`badge badge-${product.badge.toLowerCase().replace(" ", "-")}`}>
              {product.badge}
            </span>
          )}
          {discount > 0 && (
            <span className="badge badge-discount">-{discount}%</span>
          )}
        </div>

        {/* Wishlist */}
        <button
          className={`wish-btn ${wished ? "wished" : ""}`}
          onClick={() => setWished(!wished)}
          title={wished ? "Remove from wishlist" : "Add to wishlist"}
        >
          {wished ? "♥" : "♡"}
        </button>

        {/* Quick add overlay */}
        <div className="card-overlay">
          <button className="quick-view-btn">Quick View</button>
        </div>
      </div>

      <div className="card-info">
        <div className="card-category">{product.category}</div>
        <h3 className="card-name">{product.name}</h3>

        <div className="card-rating">
          {renderStars(product.rating)}
          <span className="rating-val">{product.rating}</span>
          <span className="rating-count">({product.reviews.toLocaleString()})</span>
        </div>

        <p className="card-desc">{product.description}</p>

        <div className="card-footer">
          <div className="price-group">
            <span className="price-current">₹{product.price.toLocaleString()}</span>
            {product.originalPrice && (
              <span className="price-original">₹{product.originalPrice.toLocaleString()}</span>
            )}
          </div>

          <button
            className={`add-to-cart ${added ? "added" : ""}`}
            onClick={handleAddToCart}
          >
            {added ? (
              <>✓ Added</>
            ) : (
              <>
                <span>+</span> Cart
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;
